// API Key authentication check
const headers = $input.first().json.headers || {};
const providedKey = headers['x-api-key'] || $input.first().json.api_key;
const expectedKey = $env.BARK_API_KEY;

if (expectedKey && providedKey !== expectedKey) {
  return [{ json: { valid: false, error: 'Unauthorized: invalid or missing API key' } }];
}

const text = ($input.first().json.text || '').trim();
const voicePreset = $input.first().json.voice_preset || 'v2/en_speaker_6';
const outputFormat = ($input.first().json.output_format || 'wav').toLowerCase();

// Valid Bark voice presets (exact match whitelist)
const validVoices = [
